async function main() {
    console.log('Seeding database...');
    for (const d of dapps) {
        await prisma.dapp.upsert({
            where: { url: d.url },
            update: {},
            create: {
                name: d.name,
                url: d.url,
                creatorHandle: d.creatorHandle,
                category: d.category,
                status: 'verified',
                approved: d.approved,
                flaggedForReview: d.flaggedForReview,
                needsLinkRecheck: d.needsLinkRecheck,
                clickCount: 0,
            },
        });
    }
    console.log(`Seeded ${dapps.length} dapps.`);
}
main().finally(() => prisma.$disconnect());
